  1→import { RecordId } from "surrealdb";
  2→import { HttpError } from "../http/errors";
  3→import { logError } from "../http/observability";
  4→import { jsonError, jsonResponse } from "../http/response";
  5→import type { ServerDependencies } from "../runtime/types";
  6→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  7→import { activatePolicy, buildVersionChain, createPolicy, deprecatePolicy, getPolicyById, getPolicyEdges, getVersionChain, listWorkspacePolicies } from "./policy-queries";
  8→import { validatePolicyCreateBody } from "./policy-validation";
  9→import type { PolicyRecord, PolicyRule, PolicySelector, PolicyStatus } from "./types";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Pure identity guard
 13→// ---------------------------------------------------------------------------
 14→
 15→/** Agents are denied mutation access to policies. */
 16→const isAgentIdentity = (identityType: string): boolean =>
 17→  identityType === "agent";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Identity resolution (session -> person -> identity)
 21→// ---------------------------------------------------------------------------
 22→
 23→type IdentityInfo = {
 24→  identityRecord: RecordId<"identity", string>;
 25→  identityType: string;
 26→};
 27→
 28→async function resolveIdentityFromSession(
 29→  deps: ServerDependencies,
 30→  request: Request,
 31→): Promise<IdentityInfo | Response> {
 32→  const session = await deps.auth.api.getSession({ headers: request.headers });
 33→  if (!session?.user?.id) {
 34→    return jsonError("authentication required", 401);
 35→  }
 36→
 37→  const personRecord = new RecordId("person", session.user.id);
 38→
 39→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
 40→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 41→    { person: personRecord },
 42→  );
 43→  const identityRecord = identityRows[0] as RecordId<"identity", string> | undefined;
 44→  if (!identityRecord) {
 45→    return jsonError("identity not found for user", 500);
 46→  }
 47→
 48→  const [typeRows] = await deps.surreal.query<[Array<{ type: string }>]>(
 49→    "SELECT type FROM $identity;",
 50→    { identity: identityRecord },
 51→  );
 52→  const identityType = typeRows[0]?.type;
 53→  if (!identityType) {
 54→    return jsonError("identity type not found", 500);
 55→  }
 56→
 57→  return { identityRecord, identityType };
 58→}
 59→
 60→// ---------------------------------------------------------------------------
 61→// Shared helpers
 62→// ---------------------------------------------------------------------------
 63→
 64→function isResponse(value: unknown): value is Response {
 65→  return value instanceof Response;
 66→}
 67→
 68→async function resolveWorkspace(
 69→  deps: ServerDependencies,
 70→  workspaceId: string,
 71→  logEvent: string,
 72→): Promise<RecordId<"workspace", string> | Response> {
 73→  try {
 74→    return await resolveWorkspaceRecord(deps.surreal, workspaceId);
 75→  } catch (error) {
 76→    if (error instanceof HttpError) {
 77→      return jsonError(error.message, error.status);
 78→    }
 79→    logError(logEvent, "Failed to resolve workspace", error, { workspaceId });
 80→    return jsonError("failed to resolve workspace", 500);
 81→  }
 82→}
 83→
 84→// ---------------------------------------------------------------------------
 85→// Route handler factory
 86→// ---------------------------------------------------------------------------
 87→
 88→export function createPolicyRouteHandlers(deps: ServerDependencies) {
 89→  return {
 90→    handleList: (workspaceId: string, request: Request) =>
 91→      handleListPolicies(deps, workspaceId, request),
 92→    handleDetail: (workspaceId: string, policyId: string, request: Request) =>
 93→      handlePolicyDetail(deps, workspaceId, policyId, request),
 94→    handleCreate: (workspaceId: string, request: Request) =>
 95→      handleCreatePolicy(deps, workspaceId, request),
 96→    handleActivate: (workspaceId: string, policyId: string, request: Request) =>
 97→      handleActivatePolicy(deps, workspaceId, policyId, request),
 98→    handleDeprecate: (workspaceId: string, policyId: string, request: Request) =>
 99→      handleDeprecatePolicy(deps, workspaceId, policyId, request),
100→    handleCreateVersion: (workspaceId: string, policyId: string, request: Request) =>
101→      handleCreatePolicyVersion(deps, workspaceId, policyId, request),
102→    handleVersionHistory: (workspaceId: string, policyId: string, request: Request) =>
103→      handleGetVersionHistory(deps, workspaceId, policyId, request),
104→  };
105→}
106→
107→// ---------------------------------------------------------------------------
108→// Mutation guard: resolves identity and rejects agents
109→// ---------------------------------------------------------------------------
110→
111→async function requireHumanIdentity(
112→  deps: ServerDependencies,
113→  request: Request,
114→): Promise<IdentityInfo | Response> {
115→  const identityOrError = await resolveIdentityFromSession(deps, request);
116→  if (isResponse(identityOrError)) return identityOrError;
117→
118→  if (isAgentIdentity(identityOrError.identityType)) {
119→    return jsonError("agents cannot modify policies", 403);
120→  }
121→
122→  return identityOrError;
123→}
124→
125→// ---------------------------------------------------------------------------
126→// GET /api/workspaces/:workspaceId/policies
127→// ---------------------------------------------------------------------------
128→
129→async function handleListPolicies(
130→  deps: ServerDependencies,
131→  workspaceId: string,
132→  request: Request,
133→): Promise<Response> {
134→  const identityOrError = await resolveIdentityFromSession(deps, request);
135→  if (isResponse(identityOrError)) return identityOrError;
136→
137→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.list.workspace_resolve.failed");
138→  if (isResponse(workspaceOrError)) return workspaceOrError;
139→  const workspaceRecord = workspaceOrError;
140→
141→  try {
142→    const url = new URL(request.url);
143→    const statusFilter = url.searchParams.get("status") as PolicyStatus | undefined;
144→
145→    const policies = await listWorkspacePolicies(
146→      deps.surreal,
147→      workspaceRecord,
148→      statusFilter || undefined,
149→    );
150→
151→    return jsonResponse({ policies }, 200);
152→  } catch (error) {
153→    logError("policy.list.failed", "Failed to list policies", error, { workspaceId });
154→    return jsonError("failed to list policies", 500);
155→  }
156→}
157→
158→// ---------------------------------------------------------------------------
159→// GET /api/workspaces/:workspaceId/policies/:policyId
160→// ---------------------------------------------------------------------------
161→
162→async function handlePolicyDetail(
163→  deps: ServerDependencies,
164→  workspaceId: string,
165→  policyId: string,
166→  request: Request,
167→): Promise<Response> {
168→  const identityOrError = await resolveIdentityFromSession(deps, request);
169→  if (isResponse(identityOrError)) return identityOrError;
170→
171→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.detail.workspace_resolve.failed");
172→  if (isResponse(workspaceOrError)) return workspaceOrError;
173→  const workspaceRecord = workspaceOrError;
174→
175→  try {
176→    const policy = await getPolicyById(deps.surreal, policyId, workspaceRecord);
177→    if (!policy) {
178→      return jsonError("policy not found", 404);
179→    }
180→
181→    const edges = await getPolicyEdges(deps.surreal, policyId);
182→    const versionChain = await buildVersionChain(deps.surreal, policy);
183→
184→    return jsonResponse({
185→      policy: {
186→        id: policy.id.id as string,
187→        title: policy.title,
188→        description: policy.description,
189→        version: policy.version,
190→        status: policy.status,
191→        selector: policy.selector ?? {},
192→        rules: policy.rules ?? [],
193→        human_veto_required: policy.human_veto_required ?? false,
194→        ...(policy.max_ttl ? { max_ttl: policy.max_ttl } : {}),
195→        ...(policy.supersedes ? { supersedes: policy.supersedes.id as string } : {}),
196→        created_at: policy.created_at instanceof Date ? policy.created_at.toISOString() : String(policy.created_at),
197→        ...(policy.updated_at ? {
198→          updated_at: policy.updated_at instanceof Date ? policy.updated_at.toISOString() : String(policy.updated_at),
199→        } : {}),
200→      },
201→      edges,
202→      version_chain: versionChain,
203→    }, 200);
204→  } catch (error) {
205→    logError("policy.detail.failed", "Failed to get policy detail", error, { workspaceId, policyId });
206→    return jsonError("failed to get policy detail", 500);
207→  }
208→}
209→
210→// ---------------------------------------------------------------------------
211→// POST /api/workspaces/:workspaceId/policies (stub - guarded)
212→// ---------------------------------------------------------------------------
213→
214→async function handleCreatePolicy(
215→  deps: ServerDependencies,
216→  workspaceId: string,
217→  request: Request,
218→): Promise<Response> {
219→  const guardResult = await requireHumanIdentity(deps, request);
220→  if (isResponse(guardResult)) return guardResult;
221→
222→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.create.workspace_resolve.failed");
223→  if (isResponse(workspaceOrError)) return workspaceOrError;
224→  const workspaceRecord = workspaceOrError;
225→
226→  let body: unknown;
227→  try {
228→    body = await request.json();
229→  } catch {
230→    return jsonError("invalid JSON body", 400);
231→  }
232→
233→  const validation = validatePolicyCreateBody(body as { title: unknown; description: unknown; rules: unknown });
234→  if (!validation.valid) {
235→    return jsonError(validation.errors[0], 400);
236→  }
237→
238→  const parsed = body as Record<string, unknown>;
239→
240→  try {
241→    const { policyId } = await createPolicy(deps.surreal, {
242→      title: parsed.title as string,
243→      description: parsed.description as string,
244→      selector: parsed.selector as PolicySelector | undefined,
245→      rules: parsed.rules as PolicyRule[],
246→      human_veto_required: parsed.human_veto_required as boolean | undefined,
247→      max_ttl: parsed.max_ttl as string | undefined,
248→      createdBy: guardResult.identityRecord,
249→      workspace: workspaceRecord,
250→    });
251→
252→    return jsonResponse({ policy_id: policyId }, 201);
253→  } catch (error) {
254→    logError("policy.create.failed", "Failed to create policy", error, { workspaceId });
255→    return jsonError("failed to create policy", 500);
256→  }
257→}
258→
259→// ---------------------------------------------------------------------------
260→// PATCH /api/workspaces/:workspaceId/policies/:policyId/activate (stub - guarded)
261→// ---------------------------------------------------------------------------
262→
263→/** Statuses from which activation is allowed. */
264→const ACTIVATABLE_STATUSES: ReadonlySet<PolicyStatus> = new Set<PolicyStatus>(["draft", "testing"]);
265→
266→async function handleActivatePolicy(
267→  deps: ServerDependencies,
268→  workspaceId: string,
269→  policyId: string,
270→  request: Request,
271→): Promise<Response> {
272→  const guardResult = await requireHumanIdentity(deps, request);
273→  if (isResponse(guardResult)) return guardResult;
274→
275→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.activate.workspace_resolve.failed");
276→  if (isResponse(workspaceOrError)) return workspaceOrError;
277→  const workspaceRecord = workspaceOrError;
278→
279→  try {
280→    const policyRecord = new RecordId("policy", policyId);
281→    const policy = await deps.surreal.select<PolicyRecord>(policyRecord);
282→
283→    if (!policy || (policy.workspace.id as string) !== (workspaceRecord.id as string)) {
284→      return jsonError("policy not found", 404);
285→    }
286→
287→    if (!ACTIVATABLE_STATUSES.has(policy.status)) {
288→      return jsonError(
289→        `policy must be in draft or testing status to activate (current: ${policy.status})`,
290→        409,
291→      );
292→    }
293→
294→    await activatePolicy(
295→      deps.surreal,
296→      policy,
297→      guardResult.identityRecord,
298→      workspaceRecord,
299→    );
300→
301→    return jsonResponse({ status: "active" }, 200);
302→  } catch (error) {
303→    logError("policy.activate.failed", "Failed to activate policy", error, { workspaceId, policyId });
304→    return jsonError("failed to activate policy", 500);
305→  }
306→}
307→
308→// ---------------------------------------------------------------------------
309→// PATCH /api/workspaces/:workspaceId/policies/:policyId/deprecate (stub - guarded)
310→// ---------------------------------------------------------------------------
311→
312→/** Only active policies can be deprecated. */
313→const DEPRECATABLE_STATUSES: ReadonlySet<PolicyStatus> = new Set<PolicyStatus>(["active"]);
314→
315→async function handleDeprecatePolicy(
316→  deps: ServerDependencies,
317→  workspaceId: string,
318→  policyId: string,
319→  request: Request,
320→): Promise<Response> {
321→  const guardResult = await requireHumanIdentity(deps, request);
322→  if (isResponse(guardResult)) return guardResult;
323→
324→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.deprecate.workspace_resolve.failed");
325→  if (isResponse(workspaceOrError)) return workspaceOrError;
326→  const workspaceRecord = workspaceOrError;
327→
328→  try {
329→    const policyRecord = new RecordId("policy", policyId);
330→    const policy = await deps.surreal.select<PolicyRecord>(policyRecord);
331→
332→    if (!policy || (policy.workspace.id as string) !== (workspaceRecord.id as string)) {
333→      return jsonError("policy not found", 404);
334→    }
335→
336→    if (!DEPRECATABLE_STATUSES.has(policy.status)) {
337→      return jsonError(
338→        `policy must be in active status to deprecate (current: ${policy.status})`,
339→        409,
340→      );
341→    }
342→
343→    await deprecatePolicy(deps.surreal, policyId);
344→
345→    return jsonResponse({ status: "deprecated" }, 200);
346→  } catch (error) {
347→    logError("policy.deprecate.failed", "Failed to deprecate policy", error, { workspaceId, policyId });
348→    return jsonError("failed to deprecate policy", 500);
349→  }
350→}
