405→// ---------------------------------------------------------------------------
406→// GET /api/workspaces/:workspaceId/policies/:policyId/versions
407→// ---------------------------------------------------------------------------
408→
409→async function handleGetVersionHistory(
410→  deps: ServerDependencies,
411→  workspaceId: string,
412→  policyId: string,
413→  request: Request,
414→): Promise<Response> {
415→  const identityOrError = await resolveIdentityFromSession(deps, request);
416→  if (isResponse(identityOrError)) return identityOrError;
417→
418→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.versions.workspace_resolve.failed");
419→  if (isResponse(workspaceOrError)) return workspaceOrError;
420→  const workspaceRecord = workspaceOrError;
