  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { PolicyRecord, PolicyRule, PolicySelector, PolicyStatus } from "./types";
  3→
  4→// --- Detail Response Types ---
  5→
  6→export type PolicyEdgeInfo = {
  7→  governing: Array<{ identity_id: string; created_at: string }>;
  8→  protects: Array<{ workspace_id: string; created_at: string }>;
  9→};
 10→
 11→export type PolicyVersionChainItem = {
 12→  id: string;
 13→  version: number;
 14→  status: string;
 15→  created_at: string;
 16→};
 17→
 18→// --- List Response Types ---
 19→
 20→export type PolicyListItem = {
 21→  id: string;
 22→  title: string;
 23→  status: string;
 24→  version: number;
 25→  rules_count: number;
 26→  human_veto_required: boolean;
 27→  created_at: string;
 28→  updated_at?: string;
 29→};
 30→
 31→// --- Pure Mapping ---
 32→
 33→const formatTimestamp = (value: Date | string): string =>
 34→  value instanceof Date ? value.toISOString() : String(value);
 35→
 36→const toPolicyListItem = (record: PolicyRecord): PolicyListItem => ({
 37→  id: record.id.id as string,
 38→  title: record.title,
 39→  status: record.status,
 40→  version: record.version,
 41→  rules_count: record.rules?.length ?? 0,
 42→  human_veto_required: record.human_veto_required ?? false,
 43→  created_at: formatTimestamp(record.created_at),
 44→  ...(record.updated_at ? { updated_at: formatTimestamp(record.updated_at) } : {}),
 45→});
 46→
 47→// --- Parameter Types ---
 48→
 49→type CreatePolicyParams = {
 50→  title: string;
 51→  description: string;
 52→  selector?: PolicySelector;
 53→  rules: PolicyRule[];
 54→  human_veto_required?: boolean;
 55→  max_ttl?: string;
 56→  createdBy: RecordId<"identity">;
 57→  workspace: RecordId<"workspace">;
 58→  supersedes?: RecordId<"policy">;
 59→};
 60→
 61→// --- Query Functions ---
 62→
 63→export async function loadActivePolicies(
 64→  surreal: Surreal,
 65→  identityId: RecordId<"identity">,
 66→  workspaceId: RecordId<"workspace">,
 67→): Promise<PolicyRecord[]> {
 68→  const identityResult = await surreal.query<
 69→    [Array<{ policies: PolicyRecord[] }>]
 70→  >(
 71→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
 72→    { identity: identityId },
 73→  );
 74→
 75→  const workspaceResult = await surreal.query<
 76→    [Array<{ policies: PolicyRecord[] }>]
 77→  >(
 78→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
 79→    { workspace: workspaceId },
 80→  );
 81→
 82→  const identityPolicies = identityResult[0]?.[0]?.policies ?? [];
 83→  const workspacePolicies = workspaceResult[0]?.[0]?.policies ?? [];
 84→
 85→  // Deduplicate by policy ID and filter active only
 86→  const seen = new Set<string>();
 87→  const result: PolicyRecord[] = [];
 88→  for (const policy of [...identityPolicies, ...workspacePolicies]) {
 89→    const id = policy.id.id as string;
 90→    if (!seen.has(id) && policy.status === "active") {
 91→      seen.add(id);
 92→      result.push(policy);
 93→    }
 94→  }
 95→  return result;
 96→}
 97→
 98→export async function listWorkspacePolicies(
 99→  surreal: Surreal,
100→  workspace: RecordId<"workspace">,
101→  statusFilter?: PolicyStatus,
102→): Promise<PolicyListItem[]> {
103→  const query = statusFilter
104→    ? "SELECT * FROM policy WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;"
105→    : "SELECT * FROM policy WHERE workspace = $ws ORDER BY created_at DESC;";
106→
107→  const params: Record<string, unknown> = { ws: workspace };
108→  if (statusFilter) params.status = statusFilter;
109→
110→  const [rows] = await surreal.query<[PolicyRecord[]]>(query, params);
111→
112→  return (rows ?? []).map(toPolicyListItem);
113→}
114→
115→export async function createPolicy(
116→  surreal: Surreal,
117→  params: CreatePolicyParams,
118→): Promise<{ policyId: string; policyRecord: RecordId<"policy">; version: number }> {
119→  const policyId = `policy-${crypto.randomUUID()}`;
120→  const policyRecord = new RecordId("policy", policyId);
121→
122→  if (params.supersedes) {
123→    // Atomic version assignment inside a transaction to prevent TOCTOU race.
124→    // Two concurrent requests both reading the same source version would both
125→    // compute version N+1 and create duplicate drafts. The transaction:
126→    // 1. Checks no draft already supersedes this policy (rejects duplicates)
127→    // 2. Computes MAX(version)+1 from the chain atomically
128→    // 3. Creates the new draft
129→    const content: Record<string, unknown> = {
130→      title: params.title,
131→      description: params.description,
132→      version: 1, // placeholder — overwritten atomically inside transaction
133→      status: "draft",
134→      selector: params.selector ?? {},
135→      rules: params.rules,
136→      human_veto_required: params.human_veto_required ?? false,
137→      created_by: params.createdBy,
138→      workspace: params.workspace,
139→      supersedes: params.supersedes,
140→      created_at: new Date(),
141→    };
142→    if (params.max_ttl) content.max_ttl = params.max_ttl;
143→
144→    await surreal.query(
145→      `
146→      BEGIN TRANSACTION;
147→        LET $existing = (SELECT VALUE id FROM policy
148→            WHERE supersedes = $supersedes AND status = 'draft' LIMIT 1)[0];
149→        IF $existing != NONE {
150→          THROW "a draft version already exists for this policy";
151→        };
152→        LET $maxVer = (SELECT VALUE version FROM policy
153→            WHERE workspace = $ws AND (id = $supersedes OR supersedes = $supersedes)
154→            ORDER BY version DESC LIMIT 1)[0] ?? 0;
155→        CREATE $policy CONTENT $content;
156→        UPDATE $policy SET version = $maxVer + 1;
157→      COMMIT TRANSACTION;
158→      `,
159→      {
160→        policy: policyRecord,
161→        ws: params.workspace,
162→        supersedes: params.supersedes,
163→        content,
164→      },
165→    );
166→
167→    // Read back the assigned version after the transaction commits.
168→    const [versionRows] = await surreal.query<[Array<{ version: number }>]>(
169→      "SELECT version FROM $policy;",
170→      { policy: policyRecord },
171→    );
172→    const version = versionRows[0]?.version ?? 1;
173→    return { policyId, policyRecord, version };
174→  }
175→
176→  // Non-versioned (first version) — no supersedes, always version 1.
177→  const content: Record<string, unknown> = {
178→    title: params.title,
179→    description: params.description,
180→    version: 1,
181→    status: "draft",
182→    selector: params.selector ?? {},
183→    rules: params.rules,
184→    human_veto_required: params.human_veto_required ?? false,
185→    created_by: params.createdBy,
186→    workspace: params.workspace,
187→    created_at: new Date(),
188→  };
189→  if (params.max_ttl) content.max_ttl = params.max_ttl;
190→
191→  await surreal.query("CREATE $policy CONTENT $content;", {
192→    policy: policyRecord,
193→    content,
194→  });
195→
196→  return { policyId, policyRecord, version: 1 };
197→}
198→
199→export async function activatePolicy(
200→  surreal: Surreal,
201→  policy: PolicyRecord,
202→  creatorId: RecordId<"identity">,
203→  workspaceId: RecordId<"workspace">,
204→): Promise<void> {
205→  const policyRecord = policy.id;
206→  const supersededRecord = policy.supersedes;
207→
208→  if (supersededRecord) {
209→    // D5: Version monotonicity check inside transaction to prevent TOCTOU race.
210→    // Two concurrent activations of drafts superseding the same policy would both
211→    // read the old version outside the transaction, both pass, and both commit —
212→    // violating the single-active-version invariant. Moving the guard into the
213→    // transaction makes the check-and-update atomic.
214→    await surreal.query(
215→      `
216→      BEGIN TRANSACTION;
217→        LET $oldVer = (SELECT VALUE version FROM $oldPolicy)[0];
218→        IF $oldVer != NONE AND $policyVersion <= $oldVer {
219→          THROW string::concat("version ", <string> $policyVersion,
220→            " must be greater than superseded version ", <string> $oldVer);
221→        };
222→        UPDATE $policy SET status = 'active', updated_at = time::now();
223→        RELATE $creator->governing->$policy SET created_at = time::now();
224→        RELATE $policy->protects->$workspace SET created_at = time::now();
225→        UPDATE $oldPolicy SET status = 'superseded', updated_at = time::now();
226→        DELETE governing WHERE out = $oldPolicy;
227→        DELETE protects WHERE in = $oldPolicy;
228→      COMMIT TRANSACTION;
229→    `,
230→      {
231→        policy: policyRecord,
232→        creator: creatorId,
233→        workspace: workspaceId,
234→        oldPolicy: supersededRecord,
235→        policyVersion: policy.version,
236→      },
237→    );
238→  } else {
239→    await surreal.query(
240→      `
241→      BEGIN TRANSACTION;
242→        UPDATE $policy SET status = 'active', updated_at = time::now();
243→        RELATE $creator->governing->$policy SET created_at = time::now();
244→        RELATE $policy->protects->$workspace SET created_at = time::now();
245→      COMMIT TRANSACTION;
246→    `,
247→      {
248→        policy: policyRecord,
249→        creator: creatorId,
250→        workspace: workspaceId,
251→      },
252→    );
253→  }
254→}
255→
256→export async function deprecatePolicy(
257→  surreal: Surreal,
258→  policyId: string,
259→): Promise<void> {
260→  const policyRecord = new RecordId("policy", policyId);
261→
262→  await surreal.query(
263→    `
264→    BEGIN TRANSACTION;
265→      UPDATE $policy SET status = 'deprecated', updated_at = time::now();
266→      DELETE governing WHERE out = $policy;
267→      DELETE protects WHERE in = $policy;
268→    COMMIT TRANSACTION;
269→  `,
270→    { policy: policyRecord },
271→  );
272→}
273→
274→// --- Detail Query Functions ---
275→
276→export async function getPolicyById(
277→  surreal: Surreal,
278→  policyId: string,
279→  workspace: RecordId<"workspace">,
